#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ull unsigned long long
const int N=(1 << 20) + 5,base=131;
ull has[N],tmp[N];
long long n,t,ans,cnt[N],s1[N],s2[N];
string s;
bool num[N];
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	// freopen("P7114_16.in","r",stdin);
	// freopen("P7114_16_3.out","w",stdout);
	cin>>t;
	while(t--)
	{
//		cout<<"-------\n";
		cin>>s;
		int n=s.size();
		s=" "+s;
		memset(s1,0,sizeof(s1));
		memset(s2,0,sizeof(s2));
		memset(cnt,0,sizeof(cnt));
		memset(num,0,sizeof(num));
		ans=0;
		for(int i=1;i<=n;i++)
		{
			num[s[i]-'a']=!num[s[i]-'a'];
			if(num[s[i]-'a']) s1[i]=s1[i-1]+1;
			else s1[i]=s1[i-1]-1;
			// cout<<s1[i]<<" ";
		}
		// cout<<"\n";
		memset(num,0,sizeof(num));
		s2[n+1]=0;
		for(int i=n;i>0;i--)
		{
			num[s[i]-'a']=!num[s[i]-'a'];
			if(num[s[i]-'a']) s2[i]=s2[i+1]+1;
			else s2[i]=s2[i+1]-1;
			// cout<<s2[i]<<" ";
		}
		// cout<<"\n";
		tmp[0]=1;
		for(int i=1;i<=n;i++)
		{
			tmp[i]=tmp[i-1]*base;
			has[i]=has[i-1]*base+(s[i]-'a');
			// cout<<tmp[i]<<" ";
		}
		// cout<<"\n";
		for(int i=2;i<=n;i++)
		{
			for(int j=s1[i-1];j<=26;j++)
			{
				cnt[j]++;
			}
			for(int j=i;j<n;j+=i)
			{
				if(has[i]!=(has[j]-has[j-i]*tmp[i])) break;
				if(j<n) ans+=cnt[s2[j+1]];
			}
		}
		cout<<ans<<"\n";
	}
	return 0;
}
